\label{conj:PFA}
    Suppose $\kappa$ is a limit of Woodin cardinals. Then the following hold.
    \begin{enumerate}
        \item $\Theta^{D(V,\kappa)} < \kappa^+$.
        \item $D(V,\kappa)\models AD_{\mathbb{R}}.$
    \end{enumerate}

\label{restriction} If $S$ has nonvanishing Gaussian curvature, the inequality
\begin{equation}\label{rest1}
 \| \widehat{g\mathrm{d}\sigma}\|_{L^{q}(\mathbb{R}^{d})}\lesssim \|g\|_{L^{p}(\d\sigma)}
\end{equation}
holds if and only if $q>\frac{2d}{d-1}$ and $q\geq \frac{(d+1)}{d-1}p^{\prime}$, where $\sigma$ is the surface measure.

\label{conj:main}
For any $K \in \K^d_0$ and $\Lambda \in \mathcal{L}^d$:
\begin{equation}
G(K, \Lambda) \le \prod_{i=1}^d \left\lfloor \frac{2}{\lambda_i(K, \Lambda)} + 1 \right\rfloor.
\end{equation}

\label{gen poly conj}
    Let $f$ be a polynomial with at least one irrational non-constant coefficient. For $n\sim U[N]$, the random variable 
    \begin{equation*}
        \frac{\omega(\floor{f(n)}) - \log\log N}{\sqrt{\log\log N}}
    \end{equation*}
    converges in distribution to $\mathcal{N}(0, 1)$ as $N\rightarrow\infty$.

