\label{realtypeconj}
For every untranscendable linear order $\varphi$ at least one of the following three statements applies:
\begin{itemize}
\item $\varphi$ is strongly indecomposable,
\item $\varphi$ contains an uncountable real type,
\item $\varphi = 2$.
\end{itemize}

\label{conj1}
	If $G$ is $K_5$-minor-free and $\MM$ is a correspondence 6-cover, then $G$ has 6 disjoint 
	$\MM$-colorings.  That is, $\chisc(\K_5)=6$.

Assume Conjecture \ref{ss:FS'sconjecture} for all $z$ in $Z$, which yields an equivalence
  \begin{align*}
    \bigotimes_{z\in Z}\bL_{\psi_z}:\bigotimes_{z\in Z}D(\Bun_{G,F_z},\La)\ra^\sim\bigotimes_{z\in Z}\Ind D^{\qc}_{\coh}(\LS_{\prescript{L}{}G,F_z})_{\Nilp}.
  \end{align*}
  Assume Conjecture \ref{ss:Zhu'sconjecture}.2) for all closed points $u$ in $U$, which yields an isomorphism
  \begin{align*}
    \bigotimes_u\End_{G(F_u)}(\cInd_{G(\cO_u)}^{G(F_u)}\La)\cong\bigotimes_u\End_{D_{\coh}(\LS_{\prescript{L}{}{G},F_u})}(\sO_{\LS_{\prescript{L}{}{G},\cO_u}}).
  \end{align*}
  Then the $\bigotimes_u\End_{G(F_u)}(\cInd_{G(\cO_u)}^{G(F_u)}\La)$-module
  \begin{align*}
    \loc_{Z,!}\!\La\in\bigotimes_{z\in Z}D(\Bun_{G,F_z},\La)
  \end{align*}
  corresponds under $\bigotimes_{z\in Z}\bL_{\psi_z}$ to the $\bigotimes_u\End_{D_{\coh}(\LS_{\prescript{L}{}{G},F_u})}(\sO_{\LS_{\prescript{L}{}{G},\cO_u}})$-module
  \begin{align*}
    \lres_{Z,*}(\om_{\LS_{\prescript{L}{}{G},U}})\in\bigotimes_{z\in Z}\Ind D_{\coh}^{\qc}(\LS_{\prescript{L}{}{G},F_z})_{\Nilp}.
  \end{align*}

Suppose that $Y$ is a $2$-complex. The following are equivalent. 
\begin{enumerate}
\item $b^{(2)}_2(\widetilde Y;\mathcal N(\pi_1(Y)))=0$.
\item $Y$ has non-positive towers.
\end{enumerate}

\label{conj:degree}
    For any graph $G$, the extremal ML degree is at most its Gaussian ML degree: 
    \begin{equation}\label{eq:conj-ineq}
        \emld(G) \leq \mld(G).
    \end{equation}

\label{conj:general}
    Let $\mathcal{V} :=\left(V\odot V^\top\right)^{\odot 1/2}\odot T = (\sqrt{v_{ij}v_{ji}}\tau_{ij})$. Let $(p, \zeta)\in \mathbb{R}^n\times \mathbb{R}^n$ be the unique solution of the following system of $2n$ equations:
    \begin{equation}
    \label{eq:FPE2}
    \begin{cases}
        p &= V\operatorname{diag}(1+\zeta)^2\mathbb{E}\left(\sqrt{p} \xi + r\right)_+^2\\
        \zeta &= \operatorname{diag}(1+\zeta)\mathcal{V}\operatorname{diag}(1+\zeta) \mathbb{P}\left[\sqrt{p}\xi + r\geq 0\right]\, , 
    \end{cases} 
\end{equation}
where $\xi\sim\mathcal{N}_n(0,I_n)$. Let $Y\in \mathbb{R}^n$ be the Gaussian vector defined as 
$$ Y = \left(1+\zeta\right)\left(\sqrt{p}\xi + r\right), \quad \xi\sim\mathcal{N}_n(0,I_n).$$
We denote by $Y_i$ the $i$-th component of $Y$. Let $\theta \sim \mathcal{U}([n])$, finally consider the following \textit{deterministic} probability measure $\mu_n$ defined as 
$$ \mu_n = \mathcal{L}\left(\left(Y_\theta\right)_+\right) \, , $$
then we have the following result :
$$ \boldsymbol{d}_2( \mu_n^{u^\star},\mu_n) \stackrel{\mathbb{P}}{\underset{n\to\infty}{\longrightarrow}} 0. $$

