\label{conj:Gibbs-component}
    Fix any finite set $\X$ and edge potential $h$. If 
        $\nu= \mathsf{Unif}(\X)$, then for every  $c\in (\k h_{\min},\k h_{\max})$,  $U_n$ given $\Conset_n(h,\cc)$ lies asymptotically in the set $\Gibbsnondeg(\cc)$ defined in \eqref{eqn:Gibbs-limit-splitting}.

For any $\epsilon >0$ there is a constant $K(\epsilon)$ depending only on $\epsilon$ such that whenever $a,b$ and $c$  are three coprime and non-zero integers with $a+b=c$, then 
		\begin{eqnarray*}
			c<K(\epsilon)N(abc)^{1+\epsilon}
		\end{eqnarray*}
		holds.

\label{conj:twisted_number_field_counting}
    Let $k$ be a number field, $G$ a transitive permutation group of degree $n$, and $N\normal G$ with quotient map $q:G\to G/N$ and pushforward $q_*:\Sur(G_k,G)\to \Sur(G_k,G/N)$. For each $\pi \in q_*\Sur(G_k,G)$, there exist positive constants $a,b,c > 0$ depending on $k$, $G$, $N$, and $\pi$ such that
    \[
    \#\{\psi\in q_*^{-1}(\pi) : |\disc(\psi)|\le X\}
        \sim c X^{1/a} (\log X)^{b-1}
    \]
    as $X\to \infty$.

\label{conj:log-rat-dim-3}
Let $(X,B)$ be a pair of dimension three. Assume that 
\begin{enumerate}
\item $X$ is a rational variety; 
\item $K_X+B\sim 0$; and 
\item $\mathcal{D}(X,B)\simeq_{\rm PL} S^2$. 
\end{enumerate} 
Then, the pair $(X,B)$ is log rational.

\label{conjecture-chi}
        Let $k\geq 2$ be an integer, $\chi$ a real non-principal Dirichlet character modulo $q$ and $f=\mu^{(k)}\chi$ (resp. $\mu^{(k)}g_\chi$). Then, there exists a constant $C_k>0$, such that
            \begin{align*}
                \underline{\overline{\lim}}_{x\to\infty}\frac{\sum_{n\leq x}f(n)}{x^{\frac{1}{2k}}(\log\log x)^{\frac{1}{2}-\frac{1}{2k}}(\log\log\log x)^{\frac{1}{4k}}}=\pm C_k.
            \end{align*}

\label{conj: equivalence for canonical matrices}
Let $\bF$ be a field, let $G$ be a loopless graph with orientation $D$, and let $\psi$ and $\psi'$ be $(\bF^+\rtimes \bF^{\times})$-gain functions for $G$ so that $M(\bF^+ \rtimes \bF^{\times}, \bF^+, \cA, G, \psi) = M(\bF^+ \rtimes \bF^{\times}, \bF^+, \cA, G, \psi')$, and this matroid is $3$-connected and has rank at least $3$.
Then $A(D, \psi)$ and $A(D, \psi')$ are projectively equivalent if and only if $\psi$ and $\psi'$ are switching-and-scaling equivalent.

\label{conj: representable implies incidence matrix of gain function}
Let $(G, \cB)$ be a biased graph, let $M$ be an elementary lift of the frame matroid $F(G, \cB)$ so that $M$ is $3$-connected, and let $\bF$ be a field.
If $A$ is a matrix representing $M$ over $\bF$, then there is an $(\bF^+ \rtimes \bF^{\times})$-gain function $\psi$ for $G$ so that $F(G, \cB) = F(G, \psi/\bF^+)$, $M = M(\bF^+ \rtimes \bF^{\times}, \bF^+, \cA, G, \psi)$, and $A$ is projectively equivalent to $A(D, \psi)$ for any orientation $D$ of $G$.

\label{main_thm}
Let $\bx\in \R^2$. Then, as $\eta$ goes to zero, the processes $(\bX^\eta_t(\bx))_{t\ge 0}$ converge in law to the $2$-dimensional process $(\bx+\overline{\bX}_t)_{t\ge 0}$, where:
\begin{itemize}
\item[($J_1$):] $(\overline{\bX}_t)_{t\ge 0}$ is an isotropic $\alpha$-stable process;
\item[($J_2$):] $(\overline{\bX}_t)_{t\ge 0}$ is a centred Brownian motion;
\item[($J_3$):] $(\overline{\bX}_t)_{t\ge 0}$ is a centred Brownian motion.
\end{itemize}

Let $H$ be an $n$-vertex $k$-graph with matching number at most $s$. Then
\begin{equation}\label{EMC}
	e(H)\le \max\left\{\binom{n}{k}-\binom{n-s}{k},\binom{sk+k-1}{k}\right\}.
\end{equation}

\label{log_bm}
		For origin symmetric convex bodies $K,L\subset\R^n$ with the origin in their interior and all $t\in[0,1]$
		\begin{align}\label{log_bm_ineq}
			\vol(K^tL^{1-t})\geq \vol(K)^t\vol(L)^{1-t}.
		\end{align}

\label{loc_log_bm}
		For all $p\geq 0$ and origin symmetric convex bodies $K\subset \R^n$ with nonempty interior and for all convex bodies $L\subset\R^n$ we have
		\begin{align}\label{loc_log_bm_ineq}
			\frac{V(L,K[n-1])^2}{\vol(K)}\geq \frac{n-1}{n-p}V(L,L,K[n-2])+\frac{1-p}{n(n-p)}\int_{S^{n-1}}\frac{h_L^2}{h_K}dS_K.
		\end{align}

