\label{conj:$p$-adicschanuel}
    Suppose $z_1,\ldots,z_n\in\DD_p\subset \CC_p$ are $\QQ$-linearly independent. Then
    \begin{equation*}
        \mathrm{tr.deg.}_\QQ \QQ(z_1,\ldots,z_n,\exp(z_1),\ldots,\exp(z_n))\geq n.
    \end{equation*}

\label{conj:reg-pow-conj}
For $1 \le j\le b$, we have
\begin{equation*}
\op{reg}(I_{a,b}^j) = \left\lfloor \frac{b+j+1}{2}\right\rfloor a-\left\lfloor \frac{b-j+1}{2}\right\rfloor,
\end{equation*}
and the minimal generators of $I_{a,b}^j$ form a Gr\"obner basis.

\label{conj:eq-mult-positivity}
    For any $F\in \Fix^\WG$, we have $m_F(t)\in \mathbb{Z}[t]$, and $m_F(0)=1$.
    Furthermore, $m_F(t)$ is palindromic if and only if $\sp_{W^-_F}(\mathcal{O}_\Core)_{\mathrm{tf}}$ is locally free.

\label{conj:reckless}
    There exists a collection $\{\mathcal{W}_p\}_{p\in \Hitch^\T}$ of sheaves $\mathcal{W}_p\in D^b_\T(\Hitch)$, and a collection of non-reduced $\T$-schemes $\{\mathcal{Z}_F\}_{F\in \Fix}$, satisfying the following properties:
    \begin{enumerate}[leftmargin=8mm]
        \item For each $F\in \Fix$, we have $(\mathcal{Z}_F)_\mathrm{red} = W^\llcurly_F$. For any $F_1,F_2\in \Fix$ with $F_1\preceq F_2$ we have a ``blow down'' map $\pi_{F_1}^{F_2}:\mathcal{Z}_{F_2} \to \mathcal{Z}_{F_1}$, and maps $\pi_F: \Core\to \mathcal{Z}_F$ satisfying $\pi_{F_1}^{F_2}\circ\pi_{F_2} = \pi_{F_1}$. The intersection $\bigcap_F \ker(\pi_F)$ is trivial. 
        The specialization $\sp_{W^-_F}(\mathcal{Z}_F)$ is locally free;
        \item For each $p\in \Hitch^\T$, $\mathcal{W}_p$ is supported on the Lagrangian closure $W^\ggcurly_p$, and $\mathcal{W}_p|_{W^+_p}\simeq \mathcal{O}_{W^+_p}$. Its mirror dual is a locally free sheaf $\mathcal{V}_p$ on $\Hitch^\vee$. For any $p_1,p_2\in \Hitch^\T$ and a $\T$-curve from $p_1$ to $p_2$, we have an inclusion $\mathcal{W}_{p_2}\subset \mathcal{W}_{p_1}$;
        \item For $p\in F$, we have $m(W^-_F;\mathcal{O}_{\mathcal{Z}_F}) = \chi_t(\mathcal{V}_p|_{\kappa^\vee(0)}) = \chi_t(\theta_*\mathcal{W}_p^+|_0)$. Furthermore, the value of this polynomial at $t=1$ is the multiplicity of $\Core_F$.
    \end{enumerate}

\label{conj2}
For every integer $n \geq 1$, we have
\begin{equation}
d_{BM}(\ell_{1}^n(\mathbb{C}), \ell_{\infty}^n(\mathbb{C})) = \sqrt{n}.
\end{equation}

\label{conj3}
For every integer $n \geq 1$ and all $1 \leq q \leq 2 \leq p \leq \infty$ we have
\begin{equation}
\label{lpupbound}
d_{BM}(\ell_{p}^n(\mathbb{C}), \ell_{q}^n(\mathbb{C})) = n^{\alpha},
\end{equation}
where $\alpha = \max \left \{ \frac{1}{2}-\frac{1}{p}, \frac{1}{q}-\frac{1}{2} \right \}$.

\label{conj:bip upper}
    For all bipartite graphs $H$, we have that 
   \[M_H(n)=o(\ex(n,H)).\]

\label{conj}Let $\Sigma$ be a genus $G\geq 2$ closed surface.
\begin{enumerate}
    \item  There exists a negatively curved metric $g$ on $\Sigma$ and a finite dimensional representation $\rho \in\mathrm{Hom}(\pi_1(\Sigma), \mathrm{GL}_r(\CC)) $ for which $m(g,\rho)\neq (2G-2)r$.
    \item 
    If $\rho$ is acyclic, i.e., $H^*(M,\rho)=0$, then we always have $m(g,\rho)=0$.
\end{enumerate}

For any $\epsilon >0$ there is a constant $K(\epsilon)$ depending only on $\epsilon$ such that whenever $a,b$ and $c$  are three coprime and non-zero integers with $a+b=c$, then 
