Let $\alpha > 0$, $\beta\in\mathbb{R}$. For $n\sim U[N]$, the Kolmogorov distance between the random variable 
    \begin{equation*}
        \frac{\omega(\floor{\alpha n + \beta}) - \log\log N}{\sqrt{\log\log N}}
    \end{equation*}
    and the standard Gaussian $\mathcal{N}(0, 1)$ is bounded above by $O_{\alpha, \beta}\left(\frac{1}{\sqrt{\log\log N}}\right)$ as $N\rightarrow\infty$, where the implied constant may depend on $\alpha$ and $\beta$.

There exists a sequence $\eta_N\searrow 0$ as $N\rightarrow\infty$, such that the following holds for any real numbers $\alpha > 0, \beta, \gamma$, where $\alpha$ and $\beta$ are not both rational and $\beta^2 < 4\alpha\gamma$. For $n\sim U[N]$, the Kolmogorov distance between the random variable 
    \begin{equation*}
        \frac{\omega(\floor{\alpha n^2 + \beta n + \gamma}) - \log\log N}{\sqrt{\log\log N}}
    \end{equation*}
    and the standard Gaussian $\mathcal{N}(0, 1)$ is $O_{\alpha, \beta, \gamma}(\eta_N)$ as $N\rightarrow\infty$, where the implied constant may depend on $\alpha, \beta$ and $\gamma$.

\label{conj:coeff_polynomials}
For each fixed $k \geq 0$, and all $n\ge n_0(k)$, the coefficient $a_k(n)$
of $q^k$ in $P_n(q)$ is 
a polynomial in $n$ of degree $k$. Specifically, we conjecture the following 
polynomials for the next four coefficients:
\begin{equation}
\label{eq:conj_coeff_polynomials}
\begin{split}
	 a_2(n)&=\frac{25n^2 - 49n - 116}{2},\qquad n \geq 5,\\
	 a_3(n)&=\frac{125n^3 + 15n^2 - 3104n + 1980}{6},\qquad  n \geq 7,\\
	 a_4(n)&=\frac{625 n^4 + 2650 n^3 - 36877 n^2 - 31390 n + 244728}{24},\qquad  n \geq 9,\\
	a_5(n)&=\frac{3125 n^5 + 32500 n^4 - 290925 n^3 - 1585240 n^2 + 7120060 n + 5588400}{120},\qquad  n \geq 11.
\end{split}
\end{equation}

\label{conj: bignef}
Let $f:X\to S$ be a proper surjective morphism from a normal $\mathbb{Q}$-factorial generalized K\"ahler pair $(X,B +  { \boldsymbol{\beta}})$ onto a smooth, connected, relatively compact curve $S$. Fix a point $0\in S$ and assume that the support of the boundary divisor $B$ does not contain the fiber $X_0$. 

Assume that the restriction to the central fiber $(X_0,B_0 +  { \boldsymbol{\beta}}_0)$ is a generalized klt pair, such that $K_{X_0}+B_0 +  { {\bbeta}}_0$ is nef and big. Then $K_{X}  + B +  { {\bbeta}_X}$ is nef and big over $U$ for some open neighborhood $U\subset S$ of $0$.

\label{conjcs}
    Let $X$ be a compact
pure-dimensional complex algebraic variety. Then $L_*(X)={{\rm IT}_1}_*(X)$.

\label{in:conj:type1}
    	All existence statements below refer to existence in the region $\mathcal{X}=(\{v\leq 0\}\cup \{t\leq -0.9\})\cap\{-1\leq u<0\}$.
        Let  $\phi$ denote a solution of \cref{in:thm:self_similar_stability} arising from smooth initial data.

    There exists $\epsilon>0$ (depending on the equation), such that for any $k\in\N$ the solutions satisfy
		\begin{enumerate}[label=(\alph*)]
			\item \label{type1}  for \cref{in:eq:wave_map_k} with $d\geq3$ as in \cref{in:thm:self_similar_stability} (a) for any $0\leq |\alpha|\leq k$:\begin{equation}\label{in:eq:con_rates}
