\label{conj:WeylLaw}
    Let $u_0$ be an admissible initial condition according to Definition \ref{def:AdmisInitCond} and let $R^\wyl: [1/2\delta, \zeta_\maxrm]_{\mathcal{Q}_\delta} \to \R_+$ be defined by
    \begin{equation}
        R^\wyl(\zeta) := \frac{1}{4 \delta} \int_{x_-(\zeta)}^{x_+(\zeta)} W_{0}\left(-2 \delta \zeta \ee^{-2\delta(\zeta + u_0(x))} \right) - W_{-1}\left(-2 \delta \zeta \ee^{-2\delta(\zeta + u_0(x))}\right) \, \dd x \, .
        \label{eq:RWeylLawDef}
    \end{equation}
    where $x_\pm : (1/2\delta, \zeta_\maxrm]_{\quadratrix{\delta}} \to \R$ are the turning point functions defined implicitly by
    \begin{equation}
        u_0(x_\pm(\zeta)) = E(\zeta) 
        \label{eq:TurningPointFunctDef}
    \end{equation}
    with $E$ as in \eqref{eq:TurningPointFromELevel} and such that $x_-(\zeta) \leq x_\maxrm \leq x_+(\zeta)$.
    Additionally, $W_n$ for $n \in \Z$ are the standard branches of the Lambert-$W$ function \cite[Equation 4.13.1\_1]{DLMF}.
    The asymptotics of the eigenvalues satisfy the ``ILW Weyl law''
    \begin{equation}
        R^\wyl(\zeta_n) = \left( n - \frac{1}{2} \right) \pi \epsilon + \bigO{\epsilon^2}
        \label{eq:WeylLaw}
    \end{equation}
    for $n \in \N$.
    Defining the tail integrals $\theta_\pm: [1/2\delta, \ \zeta_{\maxrm}]_{\quadratrix{\delta}} \to \R$
    \begin{equation}
        \theta_\pm(\zeta) := \im{\zeta} x_\pm(\zeta) + \int^{\pm\infty}_{x_\pm(\zeta)} \im{ \zeta + \frac{1}{2 \delta} W_{-1}\left(-2\delta \zeta \ee^{-2\delta(\zeta + u_0(x))}\right)} \, \dd x \, .
        \label{eq:TailIntegralsDef}
    \end{equation}
    Then the norming constants have the asymptotics
    \begin{align}
        c_n &= \exp \Bigg( \frac{2}{\epsilon} \theta_+(\zeta_n) \Bigg) \left| \frac{(2 \delta)^2 \zeta_n}{1 -2 \delta \zeta_n} \right| \nonumber \\
        &\Quad[2] \times \left( \int_{x_-(\zeta_n)}^{x_+(\zeta_n)} \frac{2\delta W_{-1}(-2\delta \zeta_n \ee^{-2\delta(\zeta_n + u_0(x))})}{1+W_{-1}(-2\delta \zeta_n \ee^{-2\delta(\zeta_n + u_0(x))})} - \frac{2\delta W_0(-2\delta \zeta_n \ee^{-2\delta(\zeta_n + u_0(x))})}{1+W_0(-2\delta \zeta_n \ee^{-2\delta(\zeta_n + u_0(x))})} \, \dd x \right)^{-1} \nonumber \\
        &\Quad[2] \times \left( 1 + \bigO{\epsilon^{1/6}} \right) \, . \label{eq:NormingConstAsymptoticFormula}
    \end{align}
    Finally, the reflection coefficient is small beyond all orders in $\epsilon$.

